// ═══════════════════════════════════════════════════════════════════════════════════════════
//  brainFetch — v4.9.564 — THE ONE BRAIN CALL. EVERY MODEL CALL IN THIS FILE GOES THROUGH IT.
// ═══════════════════════════════════════════════════════════════════════════════════════════
//
// THE PROBLEM IT SOLVES (measured, not assumed):
//   28 raw fetch() calls to the Anthropic API, scattered through processCommand. NO shared helper.
//   ZERO of them used prompt caching (grep: cache_control = 0 hits). So every SITUATION brief, every
//   SECURESPEND analysis, every self-read, every doorway conversation RE-BILLED ITS ENTIRE SYSTEM
//   PROMPT AT FULL LIST PRICE, every single time. That is the same bug that made a six-word question
//   cost sixty-eight cents in aura-think - except here it is multiplied across 28 sites.
//
//   Each handler was its own tiny second brain. No cache, no rung, no meter, no choke point. There was
//   nowhere to PUT a fix, which is exactly why there was no fix.
//
// WHAT IT DOES (identical signature to fetch, so all 28 sites are drop-in):
//   1. PROMPT CACHING. Anthropic only caches when `system` is an ARRAY of blocks carrying cache_control.
//      Every site here passes a plain STRING, so nothing ever cached. brainFetch converts it. ~90% off
//      the fixed prompt on every call after the first. This alone is the bulk of the backend burn.
//   2. L1 ANSWER CACHE. Identical (system+messages) -> the stored answer, from KV, NO MODEL, $0.
//      Shared truth computed once. The 10,000th identical brief costs nothing.
//   3. THE METER. Logs what every backend call actually costs, so the burn is finally VISIBLE here too.
//
// It returns a Response-shaped object, so callers keep doing r.ok / await r.json() unchanged.
// The 28 call sites were renamed mechanically (fetch -> brainFetch) and therefore pass only TWO args.
// brainFetch needs `env` to reach KV for the L1 cache. Rather than edit 28 multi-line call sites (risk),
// we capture env ONCE at the top of processCommand - which every one of those 28 calls lives inside -
// and brainFetch falls back to it. Verified by the failing test: the meter fired but L1 never hit,
// because env was undefined and `if (env && env.AURA_KV)` silently skipped. Arity bug, caught by testing.
let _BRAIN_ENV = null;


// ══ THE BRAIN CALL — PROVIDER-NEUTRAL ════════════════════════════════════════════════════════════
// aura-core grew Anthropic-native: 75 call sites hardcoded to api.anthropic.com. That is why the core
// kept billing Claude while AIMARGIN's policy engine (which governs aura-think) said "cheapest". The
// policy has to reach BOTH workers or it is not a policy, it is a preference.
//
// One entry point. Callers state intent - system, user, how many tokens - and never name a provider.
// config:policy:text decides who answers (cheapest -> Grok, balanced -> OpenAI, quality -> Claude), and
// config:brain:model still pins an exact model when someone wants one.
//
// Returns a NORMALIZED result: { ok, text, structured, usage, provider, model }. Not Anthropic blocks -
// a block array pretending to be provider-neutral is the kind of dirt that costs a future session.
const BRAIN_POLICY = {
  cheapest: { provider: "grok",      model: "grok-build-0.1" },
  balanced: { provider: "openai",    model: "gpt-4.1-nano" },
  quality:  { provider: "anthropic", model: "claude-haiku-4-5-20251001" },
  best:     { provider: "anthropic", model: "claude-opus-4-8" },
};

async function _brainRoute(env, override) {
  const pol = ((await env.AURA_KV.get("config:policy:text").catch(() => null)) || "cheapest").trim();
  const r = { ...(BRAIN_POLICY[pol] || BRAIN_POLICY.cheapest) };
  // An explicit model pin wins over policy, and tells us its provider by name shape.
  const pin = override || (await env.AURA_KV.get("config:brain:model").catch(() => null));
  if (pin && pin.trim()) {
    const m = pin.trim();
    r.model = m;
    r.provider = /^claude/i.test(m) ? "anthropic"
               : /^grok/i.test(m) ? "grok"
               : /^gemini/i.test(m) ? "gemini"
               : /^muse/i.test(m) ? "meta" : "openai";
  }
  return r;
}

// Each provider gets its REAL request/response shape - no translation layer pretending they are the same.
async function callBrain({ system, user, max_tokens = 2000, model = null, temperature }, env) {
  env = env || _BRAIN_ENV;
  const route = await _brainRoute(env, model);
  const cap = Math.max(16, Math.min(16000, parseInt(max_tokens, 10) || 2000));

  if (route.provider === "anthropic") {
    const key = env.ANTHROPIC_API_KEY || await KV.get(env, "secret:anthropic");
    if (!key) return { ok: false, error: "no Anthropic key", provider: route.provider, model: route.model };
    const r = await brainFetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { "x-api-key": key, "anthropic-version": "2023-06-01", "content-type": "application/json" },
      body: JSON.stringify({ model: route.model, max_tokens: cap, ...(system ? { system } : {}),
                             messages: [{ role: "user", content: String(user || "") }] }),
    }, env);
    const d = await r.json().catch(() => ({}));
    if (!r.ok) return { ok: false, error: (d?.error?.message || ("http " + r.status)), provider: route.provider, model: route.model };
    const text = (d?.content || []).filter((b) => b?.type === "text").map((b) => b.text).join("");
    return { ok: true, text, structured: null, provider: route.provider, model: route.model,
             usage: { in: d?.usage?.input_tokens || 0, out: d?.usage?.output_tokens || 0 } };
  }

  // Everyone else speaks chat/completions. Grok and Gemini both 404 the /responses path - proven live.
  const EP = {
    grok:   { url: "https://api.x.ai/v1/chat/completions", key: "secret:grok_api_key", envk: "XAI_API_KEY" },
    openai: { url: "https://api.openai.com/v1/chat/completions", key: "secret:openai", envk: "OPENAI_API_KEY" },
    gemini: { url: "https://generativelanguage.googleapis.com/v1beta/openai/chat/completions", key: "secret:google_api_key", envk: "GOOGLE_API_KEY" },
    meta:   { url: "https://api.meta.ai/v1/chat/completions", key: "secret:llama", envk: "LLAMA_API_KEY" },
  }[route.provider];
  if (!EP) return { ok: false, error: "unknown provider " + route.provider };
  const key = env[EP.envk] || await KV.get(env, EP.key);
  if (!key) return { ok: false, error: "no key for " + route.provider, provider: route.provider, model: route.model };
  const msgs = [];
  if (system) msgs.push({ role: "system", content: String(system) });
  msgs.push({ role: "user", content: String(user || "") });
  const r = await fetch(EP.url, {
    method: "POST",
    headers: { "Authorization": "Bearer " + key, "Content-Type": "application/json" },
    body: JSON.stringify({ model: route.model, max_tokens: cap, messages: msgs,
                           ...(temperature != null ? { temperature } : {}) }),
  });
  const d = await r.json().catch(() => ({}));
  if (!r.ok) return { ok: false, error: (d?.error?.message || JSON.stringify(d).slice(0, 200)), provider: route.provider, model: route.model };
  return { ok: true, text: d?.choices?.[0]?.message?.content || "", structured: null,
           provider: route.provider, model: route.model,
           usage: { in: d?.usage?.prompt_tokens || 0, out: d?.usage?.completion_tokens || 0 } };
}


// ══ ONE METER, BOTH FUNNELS ══════════════════════════════════════════════════════════════════════
// aura-core reaches Anthropic through TWO paths, not one: brainFetch (29 non-streaming sites) and
// callAnthropic -> callAnthropicOnce (the /chat brain, streaming, its own raw fetch). Metering only
// brainFetch left core_brain reading $0.00 while the /chat path - the busiest one - spent freely.
// That is the incomplete pattern one layer down: hook a funnel, miss its sibling. So the accounting
// lives in ONE function both call, and any third path added later calls this too.
async function meterCoreBrain(env, model, inTok, cachedIn, cacheWrite, outTok) {
  try {
    if (!env || !env.AURA_KV) return 0;
    const m = String(model || "");
    const isOpus = m.includes("opus"), isHaiku = m.includes("haiku");
    const inRate = isOpus ? 15 : isHaiku ? 1 : 3;
    const outRate = isOpus ? 75 : isHaiku ? 5 : 15;
    const fresh = Math.max(0, (inTok || 0) - (cachedIn || 0));
    const cost = (fresh * inRate + (cachedIn || 0) * inRate * 0.1
                  + (cacheWrite || 0) * inRate * 1.25 + (outTok || 0) * outRate) / 1e6;
    if (!(cost > 0)) return 0;
    const d = new Date().toISOString().slice(0, 10);
    const k = "meter:core:" + d;
    const raw = await env.AURA_KV.get(k);
    const led = raw ? JSON.parse(raw) : { day: d, cost_usd: 0, calls: 0, in: 0, cached: 0, out: 0, by_model: {} };
    led.cost_usd = +(led.cost_usd + cost).toFixed(6);
    led.calls += 1; led.in += inTok || 0; led.cached += cachedIn || 0; led.out += outTok || 0;
    led.by_model[m || "unknown"] = +(((led.by_model[m || "unknown"] || 0) + cost)).toFixed(6);
    await env.AURA_KV.put(k, JSON.stringify(led), { expirationTtl: 120 * 24 * 3600 });
    return cost;
  } catch { return 0; }
}

async function brainFetch(url, opts, env) {
  env = env || _BRAIN_ENV;
  let body;
  try { body = JSON.parse(opts && opts.body ? opts.body : "{}"); } catch { body = {}; }

  // ── STREAMING PASSES STRAIGHT THROUGH. A streamed response is a ReadableStream, not JSON - calling
  //    .json() on it would consume and destroy the stream. We still inject prompt caching (that is just
  //    a request-body change and is safe), but we do NOT cache or meter the response. Caught this by
  //    checking every one of the 28 callers for .text()/.headers use before shipping, not after.
  const isStream = body && body.stream === true;

  // ── 1. PROMPT CACHING: string system -> cached block array. The single highest-value line here. ──
  if (typeof body.system === "string" && body.system.length > 500) {
    body.system = [{ type: "text", text: body.system, cache_control: { type: "ephemeral" } }];
  }

  // streaming: caching-injected body, real fetch, untouched Response. Nothing else.
  if (isStream) return await fetch(url, { ...opts, body: JSON.stringify(body) });

  // ── 2. L1 ANSWER CACHE: has anyone already asked this exact thing? ──
  let cacheKey = null;
  try {
    if (env && env.AURA_KV) {
      const sysTxt = Array.isArray(body.system)
        ? body.system.map(b => b && b.text ? b.text : "").join("")
        : String(body.system || "");
      const msgTxt = JSON.stringify(body.messages || []);
      const buf = await crypto.subtle.digest("SHA-256",
        new TextEncoder().encode((body.model || "") + "|" + sysTxt + "|" + msgTxt));
      cacheKey = "brain:l1:" + [...new Uint8Array(buf)].map(b => b.toString(16).padStart(2, "0")).join("");
      // ══ NEVER SERVE A CACHED FAILURE ═══════════════════════════════════════════════════════
      // Same trap already closed on aura-think, still open here - different worker, identical failure.
      // 2026-07-21: PLAN failed on a shape bug, the failure got cached, and the next two attempts
      // replayed it at $0.0000 in under a second. It looked exactly like the fix had not worked. This
      // cache hid three separate fixes yesterday for the same reason: verifying a change with a request
      // already made returns the pre-fix answer, and a cached wrong answer is indistinguishable from a
      // live wrong answer.
      // A response that carried no usable text was not an answer worth keeping. Refuse to serve it, and
      // delete it so the next attempt is real.
      const hit = await env.AURA_KV.get(cacheKey);
      if (hit) {
        let usable = false;
        try {
          const j = JSON.parse(hit);
          usable = (j?.content || []).some(b => b?.type === "text" && String(b.text || "").trim().length > 0);
        } catch {}
        if (usable) {
          console.log("[BRAIN L1 HIT] $0.0000 — no model called");
          return { ok: true, status: 200, json: async () => JSON.parse(hit) };
        }
        console.warn("[BRAIN L1] cached response had no usable text - discarding and calling the model");
        try { await env.AURA_KV.delete(cacheKey); } catch {}
      }
    }
  } catch (e) { cacheKey = null; }

  // ── 3. the real call ──
  const r = await fetch(url, { ...opts, body: JSON.stringify(body) });
  if (!r.ok) return r;

  const j = await r.json();

  // ── the meter: what did this ACTUALLY cost? ──
  try {
    const u = (j && j.usage) || {};
    const inTok = u.input_tokens || 0;
    const cachedIn = u.cache_read_input_tokens || 0;
    const cacheWrite = u.cache_creation_input_tokens || 0;
    const outTok = u.output_tokens || 0;
    const isOpus = String(body.model || "").includes("opus");
    const isHaiku = String(body.model || "").includes("haiku");
    const inRate = isOpus ? 15 : isHaiku ? 1 : 3;      // $/1M — opus / haiku / sonnet
    const outRate = isOpus ? 75 : isHaiku ? 5 : 15;
    const cost = ((inTok - cachedIn) * inRate + cachedIn * inRate * 0.1 + cacheWrite * inRate * 1.25
                  + outTok * outRate) / 1e6;
    const hitRate = inTok > 0 ? ((cachedIn / inTok) * 100).toFixed(1) : "0.0";
    console.log("BRAIN " + JSON.stringify({
      model: body.model, in: inTok, cached: cachedIn, out: outTok,
      hit_rate: hitRate + "%", cost: "$" + cost.toFixed(4),
    }));

    // ══ METER aura-core's OWN BRAIN ══════════════════════════════════════════════════════════
    // This cost was already being CALCULATED here and only ever printed to the log, then discarded.
    // aura-core runs its own Claude brain - every /chat turn, llmReply, and ~29 Anthropic call sites all
    // funnel through brainFetch - and NONE of it landed in any ledger. meter:spend is written by
    // aura-think alone, so AUDIT tokens, the budget guardrail and the sanity ceiling were all blind to an
    // entire worker's spend. It never showed in the xAI reconciliation either, because it is Anthropic
    // money, and Anthropic's cost API is org-wide so it sits buried inside Claude Code's totals.
    // The number was right here the whole time. One write closes the last hole in the circle.
    await meterCoreBrain(env, body.model, inTok, cachedIn, cacheWrite, outTok);

    // ══ THE SAME LEDGER aura-think writes. ONE NUMBER, ONE TRUTH. ══════════════════════
    // Aura proved her own meter was lying: it said cents, MERCURY SAID $20 LEFT THE BANK. She trusted
    // the bank over herself - "the party being measured does not own the meter." She was right.
    // Part of the hole was HERE: 28 backend model calls in aura-core, metered to a console line that
    // evaporated, never written anywhere she could read. So the world_ledger only ever saw aura-think's
    // spending. Now BOTH workers write the same burn:<day> key, and the total is the real total.
    try {
      if (env && env.AURA_KV) {
        const day = new Date().toISOString().slice(0, 10);
        const raw = await env.AURA_KV.get("burn:" + day);
        const led = raw ? JSON.parse(raw)
                        : { day, turns: 0, cost: 0, in: 0, out: 0, cached: 0, worst_prompt: 0, by_path: {} };
        led.turns += 1;
        led.cost += cost;
        led.in += inTok;
        led.out += outTok;
        led.cached += cachedIn;
        led.worst_prompt = Math.max(led.worst_prompt || 0, inTok);
        led.by_path = led.by_path || {};
        led.by_path["aura-core"] = (led.by_path["aura-core"] || 0) + cost;
        led.last = new Date().toISOString();
        await env.AURA_KV.put("burn:" + day, JSON.stringify(led), { expirationTtl: 90 * 24 * 3600 });
      }
    } catch {}
  } catch {}

  // ── store for the next caller. 1h TTL: backend briefs go stale faster than facts. ──
  try {
    // The other half of the same fix. Guarding only the READ leaves empty responses being written and
    // then discarded on every subsequent read - correct, but wasteful and confusing. A response with no
    // usable text is not an answer; do not store it in the first place. Fixing one side and not its
    // sibling is the exact pattern this whole session has been about.
    if (cacheKey && env && env.AURA_KV) {
      const usable = (j?.content || []).some(b => b?.type === "text" && String(b.text || "").trim().length > 0);
      if (usable) await env.AURA_KV.put(cacheKey, JSON.stringify(j), { expirationTtl: 3600 });
      else console.warn("[BRAIN L1] response had no usable text - not cached");
    }
  } catch {}

  return { ok: true, status: 200, json: async () => j };
}


