        const b64 = btoa(unescape(encodeURIComponent(`Aura proposal note @ ${new Date().toISOString()}\n\n${text}\n`)));
        const put = await commitFile("AURA_PROPOSAL_NOTE.md", b64, "Aura proposes (note): " + text.slice(0, 60));
