            const { done, value } = await reader.read();
            if (done) break;
            buf += dec.decode(value, { stream: true });
            let nl;
            while ((nl = buf.indexOf("\n")) >= 0) { eat(buf.slice(0, nl).replace(/\r$/, "")); buf = buf.slice(nl + 1); }
