            const L = lines[i];
            let name = null, kind = null;
            let m;
            if ((m = L.match(/^\s*case\s+"([A-Z][A-Z0-9_]+)":/))) { name = m[1]; kind = "command"; }
            else if ((m = L.match(/^\s+([a-z_][a-zA-Z0-9_]*): tool\(/))) { name = m[1]; kind = "tool"; }
